{
  "intent": "check_and_fix",
  "intent_description": "ICMP unreachable: host 192.168.0.12 cannot reach 172.16.0.12 (25 pings sent, 0 successful). Impact: cross-subnet connectivity broken. Desired outcome: restore IP reachability between 192.168.0.0/24 and 172.16.0.0/24.",
  "target": "router1,router2",
  "needs_fix": true,
  "plan": {
    "problem": "No route or forwarding path between 192.168.0.0/24 and 172.16.0.0/24 causing 0/25 ICMP success.",
    "fix_summary": "Install static routes on the edge routers so each router has a route to the remote subnet (temporary fix until dynamic routing/OSPF adjacency is confirmed).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router1",
        "action": "add_static_route",
        "target": "172.16.0.0/24",
        "parameters": [
          "172.16.0.0/24",
          "10.0.12.2"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "192.168.0.0/24",
          "10.0.12.1"
        ]
      }
    ]
  }
}

